const results = [];
const stages = [
  { days: 30, stage: 1, subject: 'We miss your lawn! 🌿', body: 'Hi {name}, it\'s been a while! Here\'s a seasonal tip: {tip}. Ready to book? tgyardcare.com' },
  { days: 60, stage: 2, subject: 'Your Madison neighbors are loving their lawns', body: 'Hi {name}, TotalGuard is keeping hundreds of Madison yards beautiful. We\'d love to get yours back on track! tgyardcare.com' },
  { days: 90, stage: 3, subject: '10% comeback offer — just for you', body: 'Hi {name}, we want you back! Use code COMEBACK10 for 10% off your next service. Book at tgyardcare.com or call (608) 535-6057.' },
  { days: 120, stage: 4, subject: 'Last chance: 15% off to come back to TotalGuard', body: 'Hi {name}, this is your last discount offer: 15% off when you rebook. Code: LASTCHANCE15. Valid 7 days. tgyardcare.com' },
  { days: 180, stage: 5, subject: 'Should we remove you from our list?', body: 'Hi {name}, we haven\'t heard from you in a while. Should we remove you? If you\'d like to stay connected, reply STAY. Otherwise no action needed.' }
];
for (const item of $input.all()) {
  const c = item.json;
  if (!c.last_job_completed_at || !c.email) continue;
  const daysSince = Math.floor((Date.now() - new Date(c.last_job_completed_at)) / (1000*60*60*24));
  const currentStage = c.reengagement_stage || 0;
  const nextStage = stages.find(s => s.days <= daysSince && s.stage > currentStage);
  if (!nextStage) continue;
  const tip = 'water deeply twice a week and avoid cutting more than 1/3 of grass height';
  results.push({ json: { ...c, subject: nextStage.subject, body: nextStage.body.replace('{name}', c.first_name).replace('{tip}', tip), newStage: nextStage.stage } });
}
return results;
